import './index.css';

function StudentDashboard() {

  const userString =
    localStorage.getItem('user');

  let user = {};

  try {

    user = userString
      ? JSON.parse(userString)
      : {};

  } catch (error) {

    console.log(error);

    user = {};

  }

  return (

    <div className="student-dashboard">

      <h1>
        Student Dashboard
      </h1>

      <div className="student-card">

        <h2>
          Welcome
          {' '}
          {user.name || 'Student'}
        </h2>

        <p>
          Email:
          {' '}
          {user.email || 'N/A'}
        </p>

        <p>
          Role:
          {' '}
          {user.role || 'student'}
        </p>

      </div>

    </div>

  );

}

export default StudentDashboard;
